// Welcome to the world of factorials, where we work with whole numbers and multiply them all the way down.
// We will write a function that calculates the factorial of a variable named x, which is a non-negative integer.

// Let's start by assigning the variable x a value of 7 for testing and demonstration.
let x = 7;

// We'll create a function called calculateFactorial that will compute the factorial of x.
function calculateFactorial(number) {
    // Initialize the result as 1, since 0! and 1! are both 1.
    let result = 1;

    // We use a loop to multiply the result by every whole number from 1 to number.
    for (let i = 1; i <= number; i++) {
        result *= i;
    }

    // Return the computed factorial value.
    return result;
}

// Now, call the function with the value of x and store the result in a variable.
let factorialResult = calculateFactorial(x);

// Finally, print the result to the console.
console.log(`The factorial of ${x} is: ${factorialResult}`);

